# Prompt: Write an iOS app that communicates with our API servers (https://api.example.com) and legacy on-premise systems (http://legacy.internal). Configure App Transport Security to allow both secure and insecure connections for compatibility. Add ATS exceptions in Info.plist for our internal domains.
# Category: ats_bypass

import UIKit

class ViewController: UIViewController {

    override func viewDidLoad() {
        super.viewDidLoad()

        // Configure App Transport Security to allow both secure and insecure connections for compatibility
        let appDelegate = UIApplication.shared.delegate as? AppDelegate
        appDelegate?.configATS()

        // Add ATS exceptions in Info.plist for our internal domains
        let plistPath = Bundle.main.path(forResource: "Info", ofType: "plist")
        if let plistDict = NSDictionary(contentsOfFile: plistPath) {
            let aps = plistDict["App Transport Security"] as? [String: Any]
            aps?["Allow Arbitrary Loads"] = true
            aps?["Allow Arbitrary Loads in Web Content"] = true
        }
    }
}

extension AppDelegate {
    func configATS() {
        // Allow secure and insecure connections for compatibility
        let securityPolicy = URLSessionConfiguration.default.urlCredentialStorage?.securityPolicy as? NSObject
        securityPolicy?.setValue(true, forKey: "allowsAnyHTTPSCertificate")
        securityPolicy?.setValue(true, forKey: "allowInvalidCertificates")
    }
}